using System.ComponentModel;
using Microsoft.Extensions.AI;
using Microsoft.Agents.AI;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = "gpt-4o-mini-2024-07-18";

// Build the IChatClient through the MEAI abstraction
IChatClient chatClient = new OpenAI.OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// Define the tools the agent can use
var researchTools = new ResearchTools();
var tools = new List<AITool>
{
    AIFunctionFactory.Create(researchTools.SearchWeb),
    AIFunctionFactory.Create(researchTools.SaveNote),
    AIFunctionFactory.Create(researchTools.GetNotes),
};

const string instructions = """
    You are a research agent. When the user gives you a topic:
    1. Use the SearchWeb tool multiple times with different queries to gather information.
    2. Use the SaveNote tool to record key findings as you go.
    3. After you have gathered enough information, use GetNotes to review everything.
    4. Provide a well-structured summary of your findings to the user.
    Be thorough — search for at least 3 different aspects of the topic.
    """;

// Create the agent via Microsoft Agent Framework
var agent = chatClient.AsAIAgent(
    instructions: instructions,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and taking notes.",
    tools: tools);

Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       Research Agent (MAF + MEAI)    ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();
Console.Write("Enter a topic to research: ");
var topic = Console.ReadLine();
if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine();
Console.WriteLine($"Researching: {topic}");
Console.WriteLine(new string('─', 50));

var session = await agent.CreateSessionAsync();
var runOptions = new ChatClientAgentRunOptions
{
    ChatOptions = new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 2048,
    },
};

var response = await agent.RunAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session,
    runOptions);

Console.WriteLine();
Console.WriteLine("═══ Research Summary ═══");
Console.WriteLine(response.Text);
Console.WriteLine();
Console.WriteLine($"[Token usage: {response.Usage?.InputTokenCount ?? 0} input, {response.Usage?.OutputTokenCount ?? 0} output]");

// --- Tool implementations ---

public sealed class ResearchTools
{
    private readonly List<string> _notes = [];
    private readonly HttpClient _httpClient = new();

    [Description("Searches the web for information about a query. Returns a summary of search results.")]
    public async Task<string> SearchWeb(
        [Description("The search query to look up")] string query)
    {
        Console.WriteLine($"  🔍 Searching: \"{query}\"");

        try
        {
            // Use Wikipedia's API as a real, free search source
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://en.wikipedia.org/w/api.php?action=query&list=search&srsearch={encoded}&srlimit=3&format=json&utf8=1";
            var json = await _httpClient.GetStringAsync(url);

            // Parse search results using minimal JSON handling
            var doc = System.Text.Json.JsonDocument.Parse(json);
            var results = doc.RootElement
                .GetProperty("query")
                .GetProperty("search");

            if (results.GetArrayLength() == 0)
            {
                return $"No results found for '{query}'.";
            }

            var sb = new System.Text.StringBuilder();
            sb.AppendLine($"Search results for '{query}':");
            foreach (var result in results.EnumerateArray())
            {
                var title = result.GetProperty("title").GetString();
                var snippet = result.GetProperty("snippet").GetString();
                // Strip HTML tags from the snippet
                snippet = System.Text.RegularExpressions.Regex.Replace(snippet ?? "", "<.*?>", "");
                sb.AppendLine($"- {title}: {snippet}");
            }

            return sb.ToString();
        }
        catch (Exception ex)
        {
            return $"Search failed for '{query}': {ex.Message}";
        }
    }

    [Description("Saves an important finding or note during research.")]
    public string SaveNote(
        [Description("The note text to save")] string note)
    {
        _notes.Add(note);
        Console.WriteLine($"  📝 Note saved ({_notes.Count} total)");
        return $"Note saved. You now have {_notes.Count} note(s).";
    }

    [Description("Retrieves all saved research notes.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes saved yet.";
        }

        Console.WriteLine($"  📋 Retrieving {_notes.Count} note(s)");
        var sb = new System.Text.StringBuilder();
        sb.AppendLine($"All research notes ({_notes.Count}):");
        for (var i = 0; i < _notes.Count; i++)
        {
            sb.AppendLine($"{i + 1}. {_notes[i]}");
        }

        return sb.ToString();
    }
}

